import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import DashboardLayout from '../components/layout/DashboardLayout';
import StatsCard from '../components/analytics/StatsCard';
import ActivityChart from '../components/analytics/ActivityChart';
import DocumentTypeChart from '../components/analytics/DocumentTypeChart';
import { useDocuments } from '../hooks/useDocuments';
import { FileText, Upload, AlertTriangle, CheckCircle, Clock, TrendingUp } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

export default function Dashboard() {
  const { documents, loading, getStats } = useDocuments();
  const [stats, setStats] = useState({
    total: 0,
    processing: 0,
    completed: 0,
    highRisk: 0,
    avgRiskScore: 0
  });

  useEffect(() => {
    if (documents) {
      const stats = getStats();
      setStats(stats);
    }
  }, [documents]);

  const recentDocuments = documents?.slice(0, 5) || [];

  return (
    <DashboardLayout>
      <div className="space-y-8">
        {/* Header */}
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Dashboard</h1>
            <p className="text-gray-600 dark:text-gray-400 mt-1">
              Welcome back! Here's what's happening with your documents.
            </p>
          </div>
          <Link
            to="/upload"
            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors flex items-center gap-2"
          >
            <Upload className="w-4 h-4" />
            Upload Document
          </Link>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <StatsCard
            title="Total Documents"
            value={stats.total}
            icon={FileText}
            color="primary"
            trend={+12}
          />
          <StatsCard
            title="Processed"
            value={stats.completed}
            icon={CheckCircle}
            color="green"
          />
          <StatsCard
            title="In Progress"
            value={stats.processing}
            icon={Clock}
            color="yellow"
          />
          <StatsCard
            title="High Risk"
            value={stats.highRisk}
            icon={AlertTriangle}
            color="red"
            trend={-5}
          />
        </div>

        {/* Charts */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 glass-card rounded-xl p-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Activity</h3>
            <ActivityChart documents={documents} />
          </div>
          <div className="glass-card rounded-xl p-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">Document Types</h3>
            <DocumentTypeChart documents={documents} />
          </div>
        </div>

        {/* Recent Documents */}
        <div className="glass-card rounded-xl p-6">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white">Recent Documents</h3>
            <Link to="/documents" className="text-primary-600 hover:text-primary-700 text-sm flex items-center gap-1">
              View all
              <TrendingUp className="w-4 h-4" />
            </Link>
          </div>

          <div className="space-y-3">
            {recentDocuments.map((doc) => (
              <Link
                key={doc.id}
                to={`/documents/${doc.id}`}
                className="block p-4 bg-gray-50 dark:bg-gray-700/50 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg ${
                      doc.status === 'completed' ? 'bg-green-100 dark:bg-green-900/30' :
                      doc.status === 'processing' ? 'bg-yellow-100 dark:bg-yellow-900/30' :
                      'bg-gray-100 dark:bg-gray-700'
                    }`}>
                      <FileText className={`w-5 h-5 ${
                        doc.status === 'completed' ? 'text-green-600 dark:text-green-400' :
                        doc.status === 'processing' ? 'text-yellow-600 dark:text-yellow-400' :
                        'text-gray-600 dark:text-gray-400'
                      }`} />
                    </div>
                    <div>
                      <p className="font-medium text-gray-900 dark:text-white">{doc.file_name}</p>
                      <p className="text-sm text-gray-500 dark:text-gray-400">
                        Uploaded {formatDistanceToNow(new Date(doc.upload_date))} ago
                      </p>
                    </div>
                  </div>
                  
                  {doc.status === 'completed' && (
                    <div className="flex items-center gap-4">
                      <div className="text-right">
                        <span className="text-sm text-gray-500 dark:text-gray-400">Risk Score</span>
                        <div className={`text-lg font-semibold ${
                          doc.risk_score < 30 ? 'text-green-600' :
                          doc.risk_score < 60 ? 'text-yellow-600' :
                          'text-red-600'
                        }`}>
                          {doc.risk_score}
                        </div>
                      </div>
                      <div className={`px-3 py-1 rounded-full text-xs font-medium ${
                        doc.risk_score < 30 ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' :
                        doc.risk_score < 60 ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400' :
                        'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                      }`}>
                        {doc.risk_score < 30 ? 'Low Risk' : doc.risk_score < 60 ? 'Medium Risk' : 'High Risk'}
                      </div>
                    </div>
                  )}
                  
                  {doc.status === 'processing' && (
                    <div className="flex items-center gap-2">
                      <div className="w-2 h-2 bg-yellow-500 rounded-full animate-pulse"></div>
                      <span className="text-sm text-yellow-600 dark:text-yellow-400">Processing...</span>
                    </div>
                  )}
                </div>
              </Link>
            ))}

            {recentDocuments.length === 0 && !loading && (
              <div className="text-center py-12">
                <FileText className="w-12 h-12 text-gray-400 mx-auto mb-3" />
                <p className="text-gray-500 dark:text-gray-400">No documents yet</p>
                <Link
                  to="/upload"
                  className="inline-block mt-4 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors"
                >
                  Upload your first document
                </Link>
              </div>
            )}
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}