import React, { useState } from 'react';
import { FileText, Download, Maximize2, Minimize2 } from 'lucide-react';
import toast from 'react-hot-toast';

export default function DocumentViewer({ fileUrl, fileName }) {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [loading, setLoading] = useState(true);

  const getFileExtension = (filename) => {
    return filename.split('.').pop().toLowerCase();
  };

  const handleDownload = async () => {
    try {
      const response = await fetch(fileUrl);
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
      toast.success('Download started');
    } catch (error) {
      toast.error('Failed to download file');
    }
  };

  const toggleFullscreen = () => {
    setIsFullscreen(!isFullscreen);
  };

  const renderViewer = () => {
    const ext = getFileExtension(fileName);

    if (ext === 'pdf') {
      return (
        <iframe
          src={`${fileUrl}#toolbar=0`}
          className="w-full h-full min-h-[500px] rounded-lg"
          onLoad={() => setLoading(false)}
          title={fileName}
        />
      );
    } else if (ext === 'txt') {
      return (
        <div className="w-full h-full min-h-[500px] p-4 bg-gray-50 dark:bg-gray-900 rounded-lg font-mono text-sm overflow-auto">
          <pre className="text-gray-700 dark:text-gray-300 whitespace-pre-wrap">
            Loading text content...
          </pre>
        </div>
      );
    } else {
      return (
        <div className="w-full h-full min-h-[500px] flex items-center justify-center bg-gray-50 dark:bg-gray-900 rounded-lg">
          <div className="text-center">
            <FileText className="w-16 h-16 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-600 dark:text-gray-400 mb-4">
              Preview not available for this file type
            </p>
            <button
              onClick={handleDownload}
              className="inline-flex items-center gap-2 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors"
            >
              <Download className="w-4 h-4" />
              Download File
            </button>
          </div>
        </div>
      );
    }
  };

  return (
    <div className={`relative ${isFullscreen ? 'fixed inset-0 z-50 bg-white dark:bg-gray-900 p-4' : ''}`}>
      <div className="absolute top-2 right-2 flex gap-2 z-10">
        <button
          onClick={toggleFullscreen}
          className="p-2 bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm rounded-lg shadow-lg hover:bg-white dark:hover:bg-gray-800 transition-colors"
          title={isFullscreen ? 'Exit fullscreen' : 'Fullscreen'}
        >
          {isFullscreen ? (
            <Minimize2 className="w-4 h-4 text-gray-700 dark:text-gray-300" />
          ) : (
            <Maximize2 className="w-4 h-4 text-gray-700 dark:text-gray-300" />
          )}
        </button>
        <button
          onClick={handleDownload}
          className="p-2 bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm rounded-lg shadow-lg hover:bg-white dark:hover:bg-gray-800 transition-colors"
          title="Download"
        >
          <Download className="w-4 h-4 text-gray-700 dark:text-gray-300" />
        </button>
      </div>

      {loading && (
        <div className="absolute inset-0 flex items-center justify-center bg-gray-100 dark:bg-gray-800 rounded-lg">
          <div className="w-8 h-8 border-4 border-primary-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
      )}

      <div className={`${isFullscreen ? 'h-full' : 'h-[500px]'}`}>
        {renderViewer()}
      </div>
    </div>
  );
}